function getSelectedPrefabID(): string {
    try {
        if (prefabIDs.length <= 0) return "";
        prefabIndex = ((prefabIndex % prefabIDs.length) + prefabIDs.length) % prefabIDs.length;
        return prefabIDs[prefabIndex] ?? "";
    } catch(_) {
        return "";
    }
}
function changeSelectedPrefabID(delta: number): string {
    if (prefabIDs.length <= 0) return "";
    prefabIndex = ((prefabIndex + delta) % prefabIDs.length + prefabIDs.length) % prefabIDs.length;
    return getSelectedPrefabID();
}
