            function attachPlayerToPrefab(player, prefabNetObj, offset = null) {
        try {
            const rpc = player.method("RPC_AttachTo");
            if (!rpc) {
                console.log("[AttachTo] RPC_AttachTo method not found.");
                return null;
            }

            // Use Il2Cpp Vector3 instead of UnityEngine.Vector3
            const offsetVec = offset ?? zeroVector;

            console.log("[AttachTo] Calling RPC_AttachTo...");
            rpc.invoke(
                true,
                prefabNetObj,
                true,
                offsetVec
            );
            console.log("[AttachTo] Success.");

        } catch (e) {
            console.log("[AttachTo] Failed: " + e);
            smartError("[AttachTo]", e);
        }
    }
    function kickCoroutine(player) {
    const rpc = AssemblyCSharp.class("AnimalCompany.NetSessionRPCs");
    const instance = rpc.field("_instance").value;
    const userID = player.field("_userID").value;

    if (!instance || !userID) return null;

    const guid = Il2Cpp.corlib.class("System.Guid").method("Parse").invoke(userID);
    instance.method("RPC_KickPlayer").invoke(guid);
    rpc.method("KickPlayer").invoke(userID);
    }
    function gettmpfontnocrash() {
        if (tmpDefaultFontAsset && !tmpDefaultFontAsset.isNull()) return tmpDefaultFontAsset;
        if (!TMPSettingsClass) return null;
        try { tmpDefaultFontAsset = TMPSettingsClass.method("get_defaultFontAsset").invoke(); } catch(_) {}
        if (!tmpDefaultFontAsset || tmpDefaultFontAsset.isNull()) {
            try {
                const settingsInstance = TMPSettingsClass.method("get_instance").invoke();
                if (settingsInstance && !settingsInstance.isNull()) {
                    try { tmpDefaultFontAsset = settingsInstance.method("get_defaultFontAsset").invoke(); } catch(_) {}
                    if (!tmpDefaultFontAsset || tmpDefaultFontAsset.isNull()) {
                        try { tmpDefaultFontAsset = settingsInstance.field("m_defaultFontAsset").value; } catch(_) {}
                    }
                }
            } catch(_) {}
        }
        return tmpDefaultFontAsset && !tmpDefaultFontAsset.isNull() ? tmpDefaultFontAsset : null;
    }

