    function fillContainerWithItems(container: any, spawnPos: any, maxCount: number, itemIDFn: () => string) {
        let added = 0;
        for (let i = 0; i < maxCount; i++) {
            try {
                const itemID = itemIDFn();
                const item = spawnItemAtPos(itemID, spawnPos, identityQuaternion);
                if (!item || item.isNull?.()) continue;
                const gbi = item.method("GetComponent", 1).inflate(GBOClass).invoke();
                if (gbi && !gbi.isNull?.()) {
                    try { gbi.method("AddToBag").invoke(container); added++; continue; } catch(_) {}
                    try { gbi.method("AddToBagInternal").invoke(container); added++; continue; } catch(_) {}
                }
            } catch(_) {}
        }
        return added;
    }

