    function spawnGiveawayBag() {
        try {
            const handPos = leftHandTransform.method("get_position").invoke();
            const handForward = leftHandTransform.method("get_forward").invoke();
            const forwardOffset = Vector3.method("op_Multiply", 2).invoke(handForward, 0.3);
            const spawnPos = Vector3.method("op_Addition", 2).invoke(handPos, forwardOffset);
            const bagIDs = ["item_backpack_large_clover", "item_backpack_large_basketball", "item_backpack_large_base"];
            const bagResult = spawnItemPrefab(bagIDs[randInt(0, bagIDs.length - 1)], spawnPos, identityQuaternion);
            if (!bagResult || bagResult.isNull()) return null;
            const bagGBO = bagResult.method("GetComponent", 1).inflate(GBOClass).invoke();
            if (bagGBO && !bagGBO.isNull()) {
                try { bagGBO.method("set_scaleModifier").invoke(randInt(-50, 50)); } catch(_) {}
                try { bagGBO.method("set_colorHue").invoke(randInt(-127, 127)); } catch(_) {}
                try { bagGBO.method("set_colorSaturation").invoke(randInt(-20, 127)); } catch(_) {}
            }
            const bagContainer = getContainerComponent(bagResult);
            if (!bagContainer || bagContainer.isNull()) return null;
            const GIVEAWAY_BAG_ITEM_LIMIT = 20;
            setContainerCapacity(bagContainer, GIVEAWAY_BAG_ITEM_LIMIT);
            setContainerOpen(bagContainer, true);
            const insertedCount = fillContainerWithItems(bagContainer, spawnPos, GIVEAWAY_BAG_ITEM_LIMIT, () => itemIDs[randInt(0, itemIDs.length - 1)]);
            setContainerCapacity(bagContainer, GIVEAWAY_BAG_ITEM_LIMIT);
            setContainerOpen(bagContainer, false);
            return { netObj: bagResult, container: bagContainer, insertedCount };
        } catch (e) {
            console.error("spawnGiveawayBag error: " + e);
            return null;
        }
    }

