    function findLocalBackpack(player: any): any {
        try {
            if (!player || player.isNull?.()) return null;
            const playerTransform = getTransform(player);
            if (playerTransform && !playerTransform.isNull?.()) {
                try {
                    const playerGo = playerTransform.method("get_gameObject").invoke();
                    if (playerGo && !playerGo.isNull()) {
                        const bag = playerGo.method("GetComponentInChildren", 1).inflate(BackpackItemClass).invoke(true);
                        if (bag && !bag.isNull()) return bag;
                    }
                } catch(_) {}
            }
            const playerPos = getTransform(player).method("get_position").invoke();
            const allBags = Object.method("FindObjectsOfType", 1).inflate(BackpackItemClass).invoke(0);
            if (!allBags || allBags.isNull()) return null;
            let bestBag = null;
            let bestDist = 1e12;
            for (let i = 0; i < allBags.length; i++) {
                try {
                    const bag = allBags.get(i);
                    if (!bag || bag.isNull()) continue;
                    const bagGo = bag.method("get_gameObject").invoke();
                    if (!bagGo || bagGo.isNull()) continue;
                    const bagPos = getTransform(bagGo).method("get_position").invoke();
                    const dist = Vector3.method("Distance").invoke(playerPos, bagPos);
                    if (typeof dist === "number" && dist < bestDist) {
                        bestDist = dist;
                        bestBag = bag;
                    }
                } catch(_) {}
            }
            return bestBag;
        } catch(_) {
            return null;
        }
    }
