        try { pushToken(player.method("get_accountId").invoke()); } catch(_) {}
        try { pushToken(player.method("get_accountID").invoke()); } catch(_) {}
        try { pushToken(player.field("_userId").value); } catch(_) {}
        try { pushToken(player.field("_userID").value); } catch(_) {}
        try { pushToken(player.field("_accountId").value); } catch(_) {}
        try { pushToken(player.field("_accountID").value); } catch(_) {}
