                            if (!sfxList || sfxList.isNull() || sfxList.length === 0) return;
                            const idx = sfxIndex % sfxList.length;
                            const clip = sfxList.get(idx);
                            if (!clip || clip.isNull()) return;
                            SFXManager.method("PlaySFXNetworked", 4).invoke(clip, pos, 1, 0);
