    function n5SpawnPrefabByName(name: string, scale: number = 1.2): boolean {
        try {
            const hand = GTPlayerClass.field("rightHandTransform").value;
            const pos = hand.method("get_position").invoke();
            const fwd = hand.method("get_forward").invoke();
            const spawnPos = Vector3.method("op_Addition", 2).invoke(pos, Vector3.method("op_Multiply", 2).invoke(fwd, 1.5));
            PrefabGen.method("SpawnPrefab", 4).invoke(Il2Cpp.string(name), spawnPos, Quaternion.method("get_identity").invoke(), null);
            return true;
        } catch(_) { return false; }
    }

    function n5GetSelfPosition(): any {
        try {
            return GTPlayerClass.field("headCollider").value.method("get_transform").invoke().method("get_position").invoke();
        } catch(_) {
            try { return GTPlayerClass.field("rightHandTransform").value.method("get_position").invoke(); } catch(_) {}
        }
        return Vector3.method("get_zero").invoke();
    }

    function n5GetRightHandPosition(): any {
        try {
            const hand = GTPlayerClass.field("rightHandTransform").value;
            const pos = hand.method("get_position").invoke();
            const fwd = hand.method("get_forward").invoke();
            return Vector3.method("op_Addition", 2).invoke(pos, Vector3.method("op_Multiply", 2).invoke(fwd, 0.55));
        } catch(_) { return Vector3.method("get_zero").invoke(); }
    }

