    function forceDropAll(player: any) {
        try {
            const left = player.field("leftHandItem").value;
            if (left && !left.isNull()) {
                left.method("Drop").invoke();
            }
            const right = player.field("rightHandItem").value;
            if (right && !right.isNull()) {
                right.method("Drop").invoke();
            }
            const backpack = player.field("backpackItems")?.value;
            if (backpack && !backpack.isNull()) {
                const size = backpack.field("_size").value as number;
                const arr = backpack.field("_items").value;
                for (let i = 0; i < size; i++) {
                    const item = arr.get(i);
                    if (item && !item.isNull()) {
                        item.method("Drop").invoke();
                    }
                }
            }
        } catch (e) {
            console.log("forceDropAll error:", e);
        }
    }

